{
  "name": "ClimaTrack Pro",
  "description": "Professional HVAC job tracking application with time management, smart location tagging, AI-enhanced reporting, and digital signatures.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Coordinates {
  lat: number;
  lng: number;
}

export interface JobData {
  id: string;
  startTime: Date | null;
  endTime: Date | null;
  description: string;
  location: Coordinates | null;
  locationAddress?: string;
  clientSignature: string | null; // Base64 data URL
  clientName: string;
}

export enum AppStep {
  IDLE = 'IDLE',
  WORKING = 'WORKING',
  DETAILS = 'DETAILS',
  SIGNATURE = 'SIGNATURE',
  REVIEW = 'REVIEW',
}

import { GoogleGenAI } from "@google/genai";

// Initialize Gemini Client
// We assume process.env.API_KEY is available as per instructions.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Enhances a rough job description into a professional technical report.
 */
export const enhanceJobDescription = async (roughText: string): Promise<string> => {
  if (!roughText || roughText.trim().length === 0) return "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `
        You are a professional HVAC technician assistant. 
        Reword the following rough notes into a clean, professional, and technical service report paragraph suitable for a client invoice.
        Focus on clarity, technical accuracy, and polite tone. 
        Do not add invented details, just expand on what is provided.

        Rough notes: "${roughText}"
      `,
      config: {
        thinkingConfig: { thinkingBudget: 0 }, // Disable thinking for faster simple text tasks
        systemInstruction: "You are a helpful assistant for trade professionals.",
      }
    });

    return response.text || roughText;
  } catch (error) {
    console.error("Error enhancing description with Gemini:", error);
    // Fallback to original text if AI fails
    return roughText;
  }
};

import React, { useState, useEffect } from 'react';
import { Play, Square, Clock } from 'lucide-react';

interface TimerProps {
  startTime: Date | null;
  onStart: () => void;
  onStop: () => void;
  isWorking: boolean;
}

const Timer: React.FC<TimerProps> = ({ startTime, onStart, onStop, isWorking }) => {
  const [elapsed, setElapsed] = useState<string>("00:00:00");

  useEffect(() => {
    let interval: number | undefined;

    if (isWorking && startTime) {
      interval = window.setInterval(() => {
        const now = new Date();
        const diff = now.getTime() - startTime.getTime();

        const hours = Math.floor(diff / (1000 * 60 * 60));
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((diff % (1000 * 60)) / 1000);

        setElapsed(
          `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`
        );
      }, 1000);
    }

    return () => clearInterval(interval);
  }, [isWorking, startTime]);

  return (
    <div className="flex flex-col items-center justify-center p-6 bg-white rounded-2xl shadow-sm border border-slate-200 w-full max-w-md mx-auto">
      <div className="mb-6 relative">
        <div className={`w-40 h-40 rounded-full flex items-center justify-center border-4 ${isWorking ? 'border-blue-500 animate-pulse' : 'border-slate-300'}`}>
          <div className="text-3xl font-mono font-bold text-slate-700">
            {isWorking ? elapsed : "00:00:00"}
          </div>
        </div>
        {isWorking && (
            <span className="absolute top-0 right-0 flex h-3 w-3">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
          </span>
        )}
      </div>

      <div className="flex gap-4 w-full">
        {!isWorking ? (
          <button
            onClick={onStart}
            className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 px-6 rounded-xl transition-all active:scale-95"
          >
            <Play size={24} />
            Iniciar Jornada
          </button>
        ) : (
          <button
            onClick={onStop}
            className="flex-1 flex items-center justify-center gap-2 bg-red-500 hover:bg-red-600 text-white font-bold py-4 px-6 rounded-xl transition-all active:scale-95"
          >
            <Square size={24} />
            Finalizar Trabajo
          </button>
        )}
      </div>

      {startTime && isWorking && (
        <div className="mt-4 text-sm text-slate-500 flex items-center gap-1">
          <Clock size={14} />
          Iniciado a las {startTime.toLocaleTimeString()}
        </div>
      )}
    </div>
  );
};

export default Timer;

import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import { MapPin, Loader2, Navigation } from 'lucide-react';
import { Coordinates } from '../types';
import L from 'leaflet';

// Fix Leaflet default icon issue in React
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});

L.Marker.prototype.options.icon = DefaultIcon;

interface MapLocatorProps {
  location: Coordinates | null;
  setLocation: (loc: Coordinates) => void;
}

// Component to recenter map when coords change
const RecenterMap: React.FC<{ coords: Coordinates }> = ({ coords }) => {
  const map = useMap();
  useEffect(() => {
    map.setView([coords.lat, coords.lng], map.getZoom());
  }, [coords, map]);
  return null;
};

const MapLocator: React.FC<MapLocatorProps> = ({ location, setLocation }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleLocate = () => {
    setLoading(true);
    setError(null);
    if (!navigator.geolocation) {
      setError("La geolocalización no es soportada por este navegador.");
      setLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        });
        setLoading(false);
      },
      (err) => {
        setError("No se pudo obtener la ubicación. Verifique los permisos.");
        setLoading(false);
        console.error(err);
      },
      { enableHighAccuracy: true }
    );
  };

  // Initial locate if no location set
  useEffect(() => {
    if (!location) {
      handleLocate();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="w-full bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
        <h3 className="font-semibold text-slate-700 flex items-center gap-2">
          <MapPin size={18} className="text-blue-500"/> Ubicación del Trabajo
        </h3>
        <button 
          onClick={handleLocate}
          disabled={loading}
          className="text-xs bg-white border border-slate-300 px-3 py-1 rounded-md text-slate-600 hover:bg-slate-50 flex items-center gap-1"
        >
          {loading ? <Loader2 size={12} className="animate-spin" /> : <Navigation size={12} />}
          {loading ? "Buscando..." : "Actualizar"}
        </button>
      </div>

      <div className="h-64 w-full relative z-0">
        {location ? (
          <MapContainer 
            center={[location.lat, location.lng]} 
            zoom={15} 
            scrollWheelZoom={false} 
            style={{ height: '100%', width: '100%' }}
          >
            <TileLayer
              attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
              url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            />
            <Marker position={[location.lat, location.lng]}>
              <Popup>
                Ubicación registrada.
              </Popup>
            </Marker>
            <RecenterMap coords={location} />
          </MapContainer>
        ) : (
          <div className="h-full w-full flex flex-col items-center justify-center bg-slate-100 text-slate-400">
            {error ? (
               <p className="text-red-400 text-sm px-4 text-center">{error}</p>
            ) : (
               <>
                 <MapPin size={48} className="mb-2 opacity-50"/>
                 <p>Obteniendo ubicación...</p>
               </>
            )}
          </div>
        )}
      </div>

      {location && (
        <div className="p-3 bg-slate-50 text-xs text-slate-500 font-mono text-center border-t border-slate-200">
          Lat: {location.lat.toFixed(6)}, Lng: {location.lng.toFixed(6)}
        </div>
      )}
    </div>
  );
};

export default MapLocator;

import React, { useRef, useState, useEffect } from 'react';
import { Eraser, PenTool } from 'lucide-react';

interface SignaturePadProps {
  onSave: (dataUrl: string) => void;
}

const SignaturePad: React.FC<SignaturePadProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [hasSignature, setHasSignature] = useState(false);

  // Initialize canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      // Set resolution
      const ratio = Math.max(window.devicePixelRatio || 1, 1);
      canvas.width = canvas.offsetWidth * ratio;
      canvas.height = canvas.offsetHeight * ratio;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.scale(ratio, ratio);
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 2;
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getCoordinates = (event: React.MouseEvent | React.TouchEvent | MouseEvent | TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in event) {
        clientX = event.touches[0].clientX;
        clientY = event.touches[0].clientY;
    } else {
        clientX = (event as React.MouseEvent).clientX;
        clientY = (event as React.MouseEvent).clientY;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    e.preventDefault(); // Prevent scrolling on touch
    setIsDrawing(true);
    const ctx = canvasRef.current?.getContext('2d');
    const { x, y } = getCoordinates(e);
    ctx?.beginPath();
    ctx?.moveTo(x, y);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    e.preventDefault();
    const ctx = canvasRef.current?.getContext('2d');
    const { x, y } = getCoordinates(e);
    ctx?.lineTo(x, y);
    ctx?.stroke();
    if (!hasSignature) setHasSignature(true);
  };

  const endDrawing = () => {
    setIsDrawing(false);
    if (canvasRef.current && hasSignature) {
        onSave(canvasRef.current.toDataURL());
    }
  };

  const clearSignature = () => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      ctx.clearRect(0, 0, canvas.width, canvas.height); // Note: using raw width/height for clearRect
      setHasSignature(false);
      onSave("");
    }
  };

  return (
    <div className="w-full">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="bg-slate-50 p-3 border-b border-slate-200 flex justify-between items-center">
             <h3 className="font-semibold text-slate-700 flex items-center gap-2">
                <PenTool size={16} /> Firma del Cliente
            </h3>
            <button 
                onClick={clearSignature}
                className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 px-2 py-1 rounded hover:bg-red-50"
            >
                <Eraser size={12} /> Borrar
            </button>
        </div>
        <div className="relative w-full h-48 bg-white cursor-crosshair touch-none">
          <canvas
            ref={canvasRef}
            className="w-full h-full block touch-none"
            onMouseDown={startDrawing}
            onMouseMove={draw}
            onMouseUp={endDrawing}
            onMouseLeave={endDrawing}
            onTouchStart={startDrawing}
            onTouchMove={draw}
            onTouchEnd={endDrawing}
          />
           {!hasSignature && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
              <span className="text-slate-300 text-2xl font-handwriting">Firmar Aquí</span>
            </div>
          )}
        </div>
      </div>
      <p className="text-xs text-slate-400 mt-2 text-center">
        Por favor, firme dentro del cuadro blanco arriba.
      </p>
    </div>
  );
};

export default SignaturePad;

import React, { useState, useRef } from 'react';
import { 
  ClipboardCheck, 
  MapPin, 
  Clock, 
  PenTool, 
  FileText, 
  Wand2, 
  Download, 
  Mail, 
  ChevronRight,
  ChevronLeft,
  CheckCircle2
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import Timer from './components/Timer';
import MapLocator from './components/MapLocator';
import SignaturePad from './components/SignaturePad';
import { enhanceJobDescription } from './services/geminiService';
import { JobData, AppStep, Coordinates } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.IDLE);

  // Job Data State
  const [startTime, setStartTime] = useState<Date | null>(null);
  const [endTime, setEndTime] = useState<Date | null>(null);
  const [description, setDescription] = useState("");
  const [clientName, setClientName] = useState("");
  const [location, setLocation] = useState<Coordinates | null>(null);
  const [signature, setSignature] = useState<string | null>(null);
  const [isEnhancing, setIsEnhancing] = useState(false);

  // --- Handlers ---

  const handleStartJob = () => {
    setStartTime(new Date());
    setStep(AppStep.WORKING);
  };

  const handleStopJob = () => {
    setEndTime(new Date());
    setStep(AppStep.DETAILS);
  };

  const handleEnhanceDescription = async () => {
    if (!description) return;
    setIsEnhancing(true);
    const improved = await enhanceJobDescription(description);
    setDescription(improved);
    setIsEnhancing(false);
  };

  const generatePDF = () => {
    const doc = new jsPDF();
    const primaryColor = [37, 99, 235]; // Blue-600

    // Header
    doc.setFillColor(37, 99, 235);
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("REPORTE DE SERVICIO", 105, 20, { align: "center" });
    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text("ClimaTrack Pro - Servicio Técnico", 105, 30, { align: "center" });

    // Job Details
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(12);
    doc.setFont("helvetica", "bold");

    let y = 60;

    // Time
    doc.text("TIEMPO DE SERVICIO", 20, y);
    doc.setDrawColor(200, 200, 200);
    doc.line(20, y+2, 190, y+2);
    y += 10;
    doc.setFont("helvetica", "normal");
    doc.text(`Inicio: ${startTime?.toLocaleString() || 'N/A'}`, 20, y);
    y += 7;
    doc.text(`Fin: ${endTime?.toLocaleString() || 'N/A'}`, 20, y);

    // Duration calculation
    if (startTime && endTime) {
        const diffMs = endTime.getTime() - startTime.getTime();
        const diffHrs = Math.floor(diffMs / 3600000);
        const diffMins = Math.floor((diffMs % 3600000) / 60000);
        y += 7;
        doc.setFont("helvetica", "bold");
        doc.text(`Duración Total: ${diffHrs}h ${diffMins}m`, 20, y);
        doc.setFont("helvetica", "normal");
    }

    // Client
    y += 20;
    doc.setFont("helvetica", "bold");
    doc.text("CLIENTE", 20, y);
    doc.line(20, y+2, 190, y+2);
    y += 10;
    doc.setFont("helvetica", "normal");
    doc.text(`Nombre: ${clientName || 'Sin especificar'}`, 20, y);

    // Location
    y += 15;
    doc.setFont("helvetica", "bold");
    doc.text("UBICACIÓN", 20, y);
    doc.line(20, y+2, 190, y+2);
    y += 10;
    doc.setFont("helvetica", "normal");
    if (location) {
        doc.text(`Coordenadas: ${location.lat.toFixed(6)}, ${location.lng.toFixed(6)}`, 20, y);
        y+=7;
        const mapUrl = `https://www.google.com/maps/search/?api=1&query=${location.lat},${location.lng}`;
        doc.setTextColor(37, 99, 235);
        doc.textWithLink("Ver en Google Maps", 20, y, { url: mapUrl });
        doc.setTextColor(0,0,0);
    } else {
        doc.text("Ubicación no registrada", 20, y);
    }

    // Description
    y += 20;
    doc.setFont("helvetica", "bold");
    doc.text("DESCRIPCIÓN DEL TRABAJO", 20, y);
    doc.line(20, y+2, 190, y+2);
    y += 10;
    doc.setFont("helvetica", "normal");

    const splitDesc = doc.splitTextToSize(description, 170);
    doc.text(splitDesc, 20, y);
    y += (splitDesc.length * 7);

    // Signature
    if (signature) {
        if (y > 230) {
            doc.addPage();
            y = 20;
        } else {
            y += 20;
        }
        doc.setFont("helvetica", "bold");
        doc.text("CONFORMIDAD DEL CLIENTE", 20, y);
        doc.line(20, y+2, 190, y+2);
        y += 10;
        doc.addImage(signature, 'PNG', 20, y, 60, 30);
        y += 35;
        doc.setFontSize(8);
        doc.setTextColor(100, 100, 100);
        doc.text("Firmado digitalmente a través de ClimaTrack Pro", 20, y);
    }

    doc.save(`Servicio_${new Date().toISOString().slice(0,10)}.pdf`);
  };

  // --- Render Steps ---

  const renderTimer = () => (
    <div className="space-y-6 animate-fadeIn">
        <h2 className="text-xl font-bold text-slate-800 text-center">
            {step === AppStep.IDLE ? "Iniciar Nuevo Trabajo" : "Trabajo en Curso"}
        </h2>
        <Timer 
            startTime={startTime} 
            isWorking={step === AppStep.WORKING} 
            onStart={handleStartJob}
            onStop={handleStopJob}
        />
    </div>
  );

  const renderDetails = () => (
    <div className="space-y-6 animate-fadeIn">
        <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <FileText className="text-blue-600" /> Detalles del Servicio
        </h2>

        <div className="space-y-2">
            <label className="text-sm font-medium text-slate-600">Nombre del Cliente</label>
            <input 
                type="text" 
                value={clientName}
                onChange={(e) => setClientName(e.target.value)}
                placeholder="Ej. Juan Pérez"
                className="w-full p-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
            />
        </div>

        <div className="space-y-2">
            <div className="flex justify-between items-center">
                <label className="text-sm font-medium text-slate-600">Descripción del Trabajo</label>
                <button 
                    onClick={handleEnhanceDescription}
                    disabled={isEnhancing || !description}
                    className="text-xs flex items-center gap-1 text-purple-600 bg-purple-50 px-2 py-1 rounded-full hover:bg-purple-100 transition-colors disabled:opacity-50"
                >
                    <Wand2 size={12} />
                    {isEnhancing ? "Mejorando..." : "Mejorar con IA"}
                </button>
            </div>
            <textarea 
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                placeholder="Describa el trabajo realizado (ej. Instalación de AA split, carga de gas...)"
                className="w-full p-3 border border-slate-300 rounded-xl min-h-[120px] focus:ring-2 focus:ring-blue-500 outline-none"
            />
        </div>

        <MapLocator location={location} setLocation={setLocation} />

        <div className="flex justify-end pt-4">
             <button 
                onClick={() => setStep(AppStep.SIGNATURE)}
                disabled={!clientName}
                className="flex items-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-blue-700 disabled:bg-slate-300 transition-colors"
             >
                Continuar <ChevronRight size={20} />
             </button>
        </div>
    </div>
  );

  const renderSignature = () => (
    <div className="space-y-6 animate-fadeIn">
        <h2 className="text-xl font-bold text-slate-800">Firma de Conformidad</h2>
        <div className="bg-blue-50 p-4 rounded-lg border border-blue-100 text-sm text-blue-800">
            <p>Confirmo que el trabajo ha sido realizado satisfactoriamente en la ubicación y tiempo indicados.</p>
        </div>

        <SignaturePad onSave={setSignature} />

        <div className="flex justify-between pt-4">
             <button 
                onClick={() => setStep(AppStep.DETAILS)}
                className="flex items-center gap-2 text-slate-600 px-4 py-3 font-medium hover:bg-slate-100 rounded-xl"
             >
                <ChevronLeft size={20} /> Volver
             </button>
             <button 
                onClick={() => setStep(AppStep.REVIEW)}
                disabled={!signature}
                className="flex items-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-blue-700 disabled:bg-slate-300 transition-colors"
             >
                Finalizar <CheckCircle2 size={20} />
             </button>
        </div>
    </div>
  );

  const renderReview = () => (
      <div className="space-y-6 animate-fadeIn">
          <div className="text-center space-y-2 py-6">
              <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <CheckCircle2 size={32} />
              </div>
              <h2 className="text-2xl font-bold text-slate-800">¡Trabajo Completado!</h2>
              <p className="text-slate-500">El reporte está listo para ser generado.</p>
          </div>

          <div className="grid grid-cols-1 gap-4">
              <button 
                onClick={generatePDF}
                className="w-full flex items-center justify-center gap-3 bg-slate-800 text-white p-4 rounded-xl font-bold hover:bg-slate-900 transition-all shadow-lg shadow-slate-200 active:scale-95"
              >
                  <Download size={20} />
                  Descargar Reporte PDF
              </button>

              <a 
                href={`mailto:?subject=Reporte de Servicio - ${clientName}&body=Adjunto encontrará el reporte del servicio técnico realizado el ${new Date().toLocaleDateString()}.%0D%0A%0D%0APor favor adjunte el PDF descargado manualmente.`}
                className="w-full flex items-center justify-center gap-3 bg-white text-blue-600 border border-blue-200 p-4 rounded-xl font-bold hover:bg-blue-50 transition-all active:scale-95"
              >
                  <Mail size={20} />
                  Preparar Email
              </a>
          </div>

          <button 
            onClick={() => {
                setStep(AppStep.IDLE);
                setStartTime(null);
                setEndTime(null);
                setDescription("");
                setClientName("");
                setLocation(null);
                setSignature(null);
            }}
            className="w-full text-center text-slate-400 text-sm mt-8 hover:text-slate-600"
          >
              Iniciar un nuevo trabajo
          </button>
      </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
