const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.IDLE);

  // Job Data State
  const [startTime, setStartTime] = useState<Date | null>(null);
  const [endTime, setEndTime] = useState<Date | null>(null);
  const [description, setDescription] = useState("");
  const [clientName, setClientName] = useState("");
  const [location, setLocation] = useState<Coordinates | null>(null);
  const [signature, setSignature] = useState<string | null>(null);
  const [isEnhancing, setIsEnhancing] = useState(false);

  // --- Handlers ---

  const handleStartJob = () => {
    setStartTime(new Date());
    setStep(AppStep.WORKING);
  };

  const handleStopJob = () => {
    setEndTime(new Date());
    setStep(AppStep.DETAILS);
  };

  const handleEnhanceDescription = async () => {
    if (!description) return;
    setIsEnhancing(true);
    const improved = await enhanceJobDescription(description);
    setDescription(improved);
    setIsEnhancing(false);
  };

  const generatePDF = () => {
    const doc = new jsPDF();
    const primaryColor = [37, 99, 235]; // Blue-600

    // Header
    doc.setFillColor(37, 99, 235);
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("REPORTE DE SERVICIO", 105, 20, { align: "center" });
    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text("ClimaTrack Pro - Servicio Técnico", 105, 30, { align: "center" });

    // Job Details
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(12);
    doc.setFont("helvetica", "bold");

    let y = 60;

    // Time
    doc.text("TIEMPO DE SERVICIO", 20, y);
    doc.setDrawColor(200, 200, 200);
    doc.line(20, y+2, 190, y+2);
    y += 10;
    doc.setFont("helvetica", "normal");
    doc.text(`Inicio: ${startTime?.toLocaleString() || 'N/A'}`, 20, y);
    y += 7;
    doc.text(`Fin: ${endTime?.toLocaleString() || 'N/A'}`, 20, y);

    // Duration calculation
    if (startTime && endTime) {
        const diffMs = endTime.getTime() - startTime.getTime();
        const diffHrs = Math.floor(diffMs / 3600000);
        const diffMins = Math.floor((diffMs % 3600000) / 60000);
        y += 7;
        doc.setFont("helvetica", "bold");
        doc.text(`Duración Total: ${diffHrs}h ${diffMins}m`, 20, y);
        doc.setFont("helvetica", "normal");
    }

    // Client
    y += 20;
    doc.setFont("helvetica", "bold");
    doc.text("CLIENTE", 20, y);
    doc.line(20, y+2, 190, y+2);
    y += 10;
    doc.setFont("helvetica", "normal");
    doc.text(`Nombre: ${clientName || 'Sin especificar'}`, 20, y);

    // Location
    y += 15;
    doc.setFont("helvetica", "bold");
    doc.text("UBICACIÓN", 20, y);
    doc.line(20, y+2, 190, y+2);
    y += 10;
    doc.setFont("helvetica", "normal");
    if (location) {
        doc.text(`Coordenadas: ${location.lat.toFixed(6)}, ${location.lng.toFixed(6)}`, 20, y);
        y+=7;
        const mapUrl = `https://www.google.com/maps/search/?api=1&query=${location.lat},${location.lng}`;
        doc.setTextColor(37, 99, 235);
        doc.textWithLink("Ver en Google Maps", 20, y, { url: mapUrl });
        doc.setTextColor(0,0,0);
    } else {
        doc.text("Ubicación no registrada", 20, y);
    }

    // Description
    y += 20;
    doc.setFont("helvetica", "bold");
    doc.text("DESCRIPCIÓN DEL TRABAJO", 20, y);
    doc.line(20, y+2, 190, y+2);
    y += 10;
    doc.setFont("helvetica", "normal");

    const splitDesc = doc.splitTextToSize(description, 170);
    doc.text(splitDesc, 20, y);
    y += (splitDesc.length * 7);

    // Signature
    if (signature) {
        if (y > 230) {
            doc.addPage();
            y = 20;
        } else {
            y += 20;
        }
        doc.setFont("helvetica", "bold");
        doc.text("CONFORMIDAD DEL CLIENTE", 20, y);
        doc.line(20, y+2, 190, y+2);
        y += 10;
        doc.addImage(signature, 'PNG', 20, y, 60, 30);
        y += 35;
        doc.setFontSize(8);
        doc.setTextColor(100, 100, 100);
        doc.text("Firmado digitalmente a través de ClimaTrack Pro", 20, y);
    }

    doc.save(`Servicio_${new Date().toISOString().slice(0,10)}.pdf`);
  };

