import React, { useState } from 'react';
import { 
  ClipboardCheck, 
  MapPin, 
  Clock, 
  PenTool, 
  FileText, 
  Wand2, 
  Download, 
  Mail, 
  ChevronRight,
  ChevronLeft,
  CheckCircle2,
  User,
  HardHat
} from 'lucide-react';
import jsPDF from 'jspdf';
import Timer from './components/Timer';
import MapLocator from './components/MapLocator';
import SignaturePad from './components/SignaturePad';
import { enhanceJobDescription } from './services/geminiService';
import { JobData, AppStep, Coordinates } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.IDLE);

  // Job Data State
  const [startTime, setStartTime] = useState<Date | null>(null);
  const [endTime, setEndTime] = useState<Date | null>(null);

  // Text Inputs
  const [description, setDescription] = useState("");
  const [clientName, setClientName] = useState("");
  const [workerName, setWorkerName] = useState("");
  const [manualAddress, setManualAddress] = useState("");

  // Location
  const [location, setLocation] = useState<Coordinates | null>(null);

  // Signatures
  const [signature, setSignature] = useState<string | null>(null); // Client
  const [workerSignature, setWorkerSignature] = useState<string | null>(null); // Worker

  // Loading State
  const [isEnhancing, setIsEnhancing] = useState(false);

  // --- Handlers ---

  const handleStartJob = () => {
    setStartTime(new Date());
    setStep(AppStep.WORKING);
  };

  const handleStopJob = () => {
    setEndTime(new Date());
    setStep(AppStep.DETAILS);
  };

  const handleEnhanceDescription = async () => {
    if (!description) return;
    setIsEnhancing(true);
    const improved = await enhanceJobDescription(description);
    setDescription(improved);
    setIsEnhancing(false);
  };

  const generatePDF = () => {
    const doc = new jsPDF();

    // Harti Electrocool Brand Colors
    const colorPrimary = [37, 99, 235];    // Blue (Tailwind Blue-600)
    const colorAccent = [249, 115, 22];    // Orange (Tailwind Orange-500)
    const colorDark = [30, 41, 59];        // Slate-800
    const colorLight = [241, 245, 249];    // Slate-100

    // --- Header Section ---
    doc.setFillColor(colorPrimary[0], colorPrimary[1], colorPrimary[2]);
    doc.rect(0, 0, 210, 45, 'F'); // Blue Top Bar

    // Company Title / Logo Area
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(26);
    doc.text("HARTI", 15, 20);
    doc.setTextColor(colorAccent[0], colorAccent[1], colorAccent[2]); // Orange text for Electrocool part
    doc.text("ELECTROCOOL", 15, 30);

    doc.setFontSize(10);
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "normal");
    doc.text("CLIMATIZACIÓN Y SERVICIOS TÉCNICOS", 15, 38);

    // Document Title (Right Side)
    doc.setFontSize(18);
    doc.text("PARTE DE TRABAJO", 195, 20, { align: "right" });
    doc.setFontSize(10);
    doc.text(`Fecha: ${new Date().toLocaleDateString()}`, 195, 30, { align: "right" });
    doc.text(`Ref: ${Date.now().toString().slice(-6)}`, 195, 36, { align: "right" });

    // --- Content Start Y Position ---
    let y = 60;

    // --- Section: General Info (Grid Layout) ---
    doc.setDrawColor(200, 200, 200);

    // Column 1: Worker Info
    doc.setFillColor(colorLight[0], colorLight[1], colorLight[2]);
    doc.roundedRect(15, y, 85, 35, 2, 2, 'F');
    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    doc.text("TÉCNICO RESPONSABLE", 20, y + 8);
    doc.setFontSize(12);
    doc.setTextColor(colorDark[0], colorDark[1], colorDark[2]);
    doc.setFont("helvetica", "bold");
    doc.text(workerName || "No especificado", 20, y + 18);

    // Column 2: Client Info
    doc.setFillColor(colorLight[0], colorLight[1], colorLight[2]);
    doc.roundedRect(110, y, 85, 35, 2, 2, 'F');
    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    doc.setFont("helvetica", "normal");
    doc.text("CLIENTE", 115, y + 8);
    doc.setFontSize(12);
    doc.setTextColor(colorDark[0], colorDark[1], colorDark[2]);
    doc.setFont("helvetica", "bold");
    doc.text(clientName || "No especificado", 115, y + 18);

    y += 45;

    // --- Section: Time & Location ---

