    doc.setLineWidth(1);
    doc.line(15, y, 195, y);
    doc.setFontSize(11);
    doc.setTextColor(colorPrimary[0], colorPrimary[1], colorPrimary[2]);
    doc.setFont("helvetica", "bold");
    doc.text("DETALLES DE TIEMPO Y UBICACIÓN", 15, y - 3);

    y += 10;

    // Calculate Duration
