    }
    if (!addressText) addressText = "No especificada";

    doc.text(addressText, 50, y);

    // Maps Link if coords exist
    if (location) {
        y += 7;
        const mapUrl = `https://www.google.com/maps/search/?api=1&query=${location.lat},${location.lng}`;
        doc.setTextColor(colorPrimary[0], colorPrimary[1], colorPrimary[2]);
        doc.setFontSize(9);
        doc.textWithLink("(Ver en Google Maps)", 50, y, { url: mapUrl });
    }

    y += 20;

    // --- Section: Description ---

    doc.setDrawColor(colorAccent[0], colorAccent[1], colorAccent[2]);
    doc.line(15, y, 195, y);
    doc.setFontSize(11);
    doc.setTextColor(colorPrimary[0], colorPrimary[1], colorPrimary[2]);
    doc.setFont("helvetica", "bold");
    doc.text("INFORME DEL TRABAJO REALIZADO", 15, y - 3);

    y += 10;
    doc.setFontSize(10);
    doc.setTextColor(0, 0, 0);
    doc.setFont("helvetica", "normal");

    const splitDesc = doc.splitTextToSize(description, 180);
    doc.text(splitDesc, 15, y);

    y += (splitDesc.length * 6) + 20;

    // --- Section: Signatures ---

    // Check if we need a new page
    if (y > 220) {
        doc.addPage();
        y = 40;
    }

    // Boxes for signatures
    const boxY = y;
    const boxHeight = 50;

    // Worker Signature Box
    doc.setDrawColor(200, 200, 200);
    doc.setLineWidth(0.5);
    doc.rect(15, boxY, 85, boxHeight);
    doc.setFontSize(8);
    doc.setTextColor(100, 100, 100);
    doc.text("FIRMA DEL TÉCNICO", 20, boxY + 8);

    if (workerSignature) {
        doc.addImage(workerSignature, 'PNG', 25, boxY + 10, 60, 30);
    }
    doc.setFontSize(10);
    doc.setTextColor(0,0,0);
    doc.text(workerName, 57, boxY + 45, { align: 'center'});

    // Client Signature Box
    doc.rect(110, boxY, 85, boxHeight);
    doc.setFontSize(8);
    doc.setTextColor(100, 100, 100);
    doc.text("CONFORMIDAD DEL CLIENTE", 115, boxY + 8);

    if (signature) {
        doc.addImage(signature, 'PNG', 120, boxY + 10, 60, 30);
    }
    doc.setFontSize(10);
    doc.setTextColor(0,0,0);
    doc.text(clientName, 152, boxY + 45, { align: 'center'});

    // Footer
    const pageHeight = doc.internal.pageSize.height;
    doc.setFillColor(colorLight[0], colorLight[1], colorLight[2]);
    doc.rect(0, pageHeight - 20, 210, 20, 'F');
    doc.setFontSize(8);
    doc.setTextColor(150, 150, 150);
    doc.text("Harti Electrocool Climatización - Documento generado digitalmente con ClimaTrack Pro", 105, pageHeight - 8, { align: "center" });

    doc.save(`Parte_Harti_${clientName.replace(/\s/g, '_')}_${new Date().toISOString().slice(0,10)}.pdf`);
  };

  // --- Render Steps ---

  const renderTimer = () => (
    <div className="space-y-6 animate-fadeIn">
        <h2 className="text-xl font-bold text-slate-800 text-center">
