// *** INSTRUCCIONES PARA EL LOGO ***
// Pega tu código Base64 del logo entre las comillas de abajo.
// Debe empezar por "data:image/png;base64,..." o "data:image/jpeg;base64,..."
const COMPANY_LOGO_BASE64 = ""; 

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.IDLE);

  // Job Data State
  const [startTime, setStartTime] = useState<Date | null>(null);
