    const colorAccent = [249, 115, 22];    // Orange (Tailwind Orange-500)
    const colorDark = [30, 41, 59];        // Slate-800
    const colorLight = [241, 245, 249];    // Slate-100

    // --- Header Section ---
    doc.setFillColor(colorPrimary[0], colorPrimary[1], colorPrimary[2]);
    doc.rect(0, 0, 210, 45, 'F'); // Blue Top Bar

    // Logo Logic
    let titleX = 15;
    if (COMPANY_LOGO_BASE64) {
        try {
            // Draw Logo (assuming square-ish aspect ratio, adjust as needed)
            // Position x=15, y=5, width=35, height=35
            doc.addImage(COMPANY_LOGO_BASE64, 'PNG', 15, 5, 35, 35);
            titleX = 55; // Move text to the right
        } catch (e) {
            console.error("Error adding logo to PDF:", e);
            titleX = 15; // Fallback position
        }
    }

    // Company Title
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(26);
    doc.text("HARTI", titleX, 20);
    doc.setTextColor(colorAccent[0], colorAccent[1], colorAccent[2]); // Orange text for Electrocool part
    doc.text("ELECTROCOOL", titleX, 30);

    doc.setFontSize(10);
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "normal");
    doc.text("CLIMATIZACIÓN Y SERVICIOS TÉCNICOS", titleX, 38);

    // Document Title (Right Side)
    doc.setFontSize(18);
    doc.text("PARTE DE TRABAJO", 195, 20, { align: "right" });
    doc.setFontSize(10);
    doc.text(`Fecha: ${new Date().toLocaleDateString()}`, 195, 30, { align: "right" });
    doc.text(`Ref: ${Date.now().toString().slice(-6)}`, 195, 36, { align: "right" });

    // --- Content Start Y Position ---
    let y = 60;

    // --- Section: General Info (Grid Layout) ---
    doc.setDrawColor(200, 200, 200);

    // Column 1: Worker Info
    doc.setFillColor(colorLight[0], colorLight[1], colorLight[2]);
    doc.roundedRect(15, y, 85, 35, 2, 2, 'F');
    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    doc.text("TÉCNICO RESPONSABLE", 20, y + 8);
    doc.setFontSize(12);
    doc.setTextColor(colorDark[0], colorDark[1], colorDark[2]);
    doc.setFont("helvetica", "bold");
    doc.text(workerName || "No especificado", 20, y + 18);

    // Column 2: Client Info
    doc.setFillColor(colorLight[0], colorLight[1], colorLight[2]);
    doc.roundedRect(110, y, 85, 35, 2, 2, 'F');
    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    doc.setFont("helvetica", "normal");
    doc.text("CLIENTE", 115, y + 8);
    doc.setFontSize(12);
    doc.setTextColor(colorDark[0], colorDark[1], colorDark[2]);
    doc.setFont("helvetica", "bold");
    doc.text(clientName || "No especificado", 115, y + 18);

    y += 45;

    // --- Section: Time & Location ---

    // Header for this section
    doc.setDrawColor(colorAccent[0], colorAccent[1], colorAccent[2]);
    doc.setLineWidth(1);
    doc.line(15, y, 195, y);
    doc.setFontSize(11);
    doc.setTextColor(colorPrimary[0], colorPrimary[1], colorPrimary[2]);
    doc.setFont("helvetica", "bold");
    doc.text("DETALLES DE TIEMPO Y UBICACIÓN", 15, y - 3);

    y += 10;

    // Calculate Duration
    let duration = "0h 0m";
    if (startTime && endTime) {
        const diffMs = endTime.getTime() - startTime.getTime();
        const diffHrs = Math.floor(diffMs / 3600000);
