          </div>
          <div className="flex gap-1.5">
             {[AppStep.IDLE, AppStep.WORKING, AppStep.DETAILS, AppStep.SIGNATURE, AppStep.REVIEW].map((s, i) => (
                 <div 
                    key={s} 
