import { User, Task } from '../types';

const USERS_KEY = 'climatrack_users_v1';
const TASKS_KEY = 'climatrack_tasks_v1';

// Initialize default admin if not exists
const initStorage = () => {
  const users = getUsers();
  if (users.length === 0) {
    // We don't store the hardcoded admin here to prevent overwrite issues, 
    // but we return it in calls if needed or handle it in Auth logic.
    // However, for consistency, let's store created workers here.
  }
};

export const getUsers = (): User[] => {
  const stored = localStorage.getItem(USERS_KEY);
  return stored ? JSON.parse(stored) : [];
};

export const createUser = (user: User): boolean => {
  const users = getUsers();
  if (users.find(u => u.username === user.username)) {
    return false; // User exists
  }
  users.push(user);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
  return true;
};

export const getTasks = (): Task[] => {
  const stored = localStorage.getItem(TASKS_KEY);
  return stored ? JSON.parse(stored) : [];
};

export const createTask = (task: Task) => {
  const tasks = getTasks();
  tasks.push(task);
  localStorage.setItem(TASKS_KEY, JSON.stringify(tasks));
};

export const updateTaskStatus = (taskId: string, isCompleted: boolean) => {
  const tasks = getTasks();
  const index = tasks.findIndex(t => t.id === taskId);
  if (index !== -1) {
    tasks[index].isCompleted = isCompleted;
    localStorage.setItem(TASKS_KEY, JSON.stringify(tasks));
  }
};

export const getTasksForUser = (username: string): Task[] => {
  const tasks = getTasks();
  return tasks.filter(t => t.assignedTo === username);
};

initStorage();

