    </div>
  );

  const renderSignature = () => (
    <div className="space-y-8 animate-fadeIn pb-20">
        <h2 className="text-xl font-bold text-slate-800 border-b border-slate-200 pb-2">Firmas y Conformidad</h2>

        <div className="space-y-2">
