             <SignaturePad onSave={setWorkerSignature} title="Firma del Técnico" />
        </div>

        <div className="space-y-2">
            <h3 className="font-semibold text-slate-700 text-sm uppercase tracking-wide">Firma del Cliente ({clientName})</h3>
