  const [startTime, setStartTime] = useState<Date | null>(null);
  const [endTime, setEndTime] = useState<Date | null>(null);
  const [description, setDescription] = useState("");
  const [materials, setMaterials] = useState("");
  const [price, setPrice] = useState("");
  const [clientName, setClientName] = useState("");
  const [workerName, setWorkerName] = useState("");
  const [manualAddress, setManualAddress] = useState("");
  const [location, setLocation] = useState<Coordinates | null>(null);
  const [signature, setSignature] = useState<string | null>(null);
  const [workerSignature, setWorkerSignature] = useState<string | null>(null);
  const [isEnhancing, setIsEnhancing] = useState(false);

  // --- Effects ---
  // Auto-fill worker name if logged in
  useEffect(() => {
    if (currentUser) {
      setWorkerName(currentUser.fullName);
    }
  }, [currentUser]);

  // Load Admin Lists whenever view or trigger changes
  useEffect(() => {
      if (currentUser?.role === 'ADMIN') {
          setAdminUsersList(Storage.getUsers());
          setAdminTasksList(Storage.getTasks());
      }
  }, [currentUser, view, refreshTrigger]);

  // --- Auth Handlers ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError("");

    // Admin Hardcoded Check
    if (loginUser === "admin" && loginPass === "123456789") {
        setCurrentUser({ username: "admin", role: "ADMIN", fullName: "Administrador" });
        setView(AppView.DASHBOARD);
        return;
    }

    // Check Stored Users
    const users = Storage.getUsers();
    const found = users.find(u => u.username === loginUser && u.password === loginPass);

    if (found) {
        setCurrentUser(found);
        setView(AppView.DASHBOARD);
    } else {
        setLoginError("Usuario o contraseña incorrectos.");
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setLoginUser("");
    setLoginPass("");
    setView(AppView.LOGIN);
    // Reset Report State
    setStep(AppStep.IDLE);
    setStartTime(null);
    setEndTime(null);
    setDescription("");
    setMaterials("");
    setPrice("");
    setClientName("");
    setWorkerName(""); // Clear worker name too
    setManualAddress("");
    setLocation(null);
    setSignature(null);
    setWorkerSignature(null);
  };

  // --- Admin Handlers ---
  const handleCreateUser = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newUserUser || !newUserPass || !newUserFullname) return;

      const success = Storage.createUser({
          username: newUserUser,
          password: newUserPass,
          fullName: newUserFullname,
          role: 'WORKER'
      });

      if (success) {
          setUserMsg("Usuario creado correctamente.");
          setNewUserUser("");
          setNewUserPass("");
          setNewUserFullname("");
          setRefreshTrigger(prev => prev + 1); // Refresh user list
          setTimeout(() => setUserMsg(""), 3000);
      } else {
          setUserMsg("El usuario ya existe.");
      }
  };

  const handleDeleteUser = (e: React.MouseEvent, username: string) => {
      e.preventDefault();
      e.stopPropagation(); // Stop bubbling
