          title: newTaskTitle,
          location: newTaskLoc,
          description: newTaskDesc,
          assignedTo: newTaskAssignee,
          createdBy: currentUser?.username || 'admin',
          isCompleted: false,
          createdAt: Date.now()
      };

      Storage.createTask(newTask);
      setTaskMsg("Trabajo asignado correctamente.");
      setNewTaskTitle("");
      setNewTaskLoc("");
      setNewTaskDesc("");
      setRefreshTrigger(prev => prev + 1); // Refresh list
