          const unsubscribe = Storage.subscribeToWorkerTasks(currentUser.username, (updatedTasks) => {
              setTasks(updatedTasks);
          });
          return () => unsubscribe();
      }
  }, [currentUser]);

  const toggleTask = async (taskId: string, currentStatus: boolean) => {
