        const effectiveWorkMs = Math.max(0, totalSpan - totalPausedMs);

        const diffHrs = Math.floor(effectiveWorkMs / 3600000);
        const diffMins = Math.floor((effectiveWorkMs % 3600000) / 60000);
        duration = `${diffHrs}h ${diffMins}m`;
